import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Soniphorm","text":"Smart Contact Mic","tagline":"A programmable contact microphone. Listen to the world, turn it into an instrument.","actions":[{"theme":"brand","text":"Get Started","link":"/getting-started/"},{"theme":"alt","text":"Module Reference","link":"/modules/"},{"theme":"alt","text":"Open Patcher","link":"https://soniphorm.com/patcher"}]},"features":[{"title":"Contact mic with a brain","details":"A sensitive piezo pickup and a full DSP engine on one board. Clip it to anything that vibrates and process the signal live."},{"title":"Visual patching","details":"Drag modules onto a canvas, connect them with cables, hear the result instantly. No code, no Arduino."},{"title":"40+ modules","details":"Oscillators, filters, granular, samplers, drum machines, sequencers, MIDI -- a full modular synth running on the SCM."},{"title":"Pocket-sized rig","details":"Power and control from a phone. Plug into an Android device over USB-C and play the SCM over Bluetooth MIDI -- no laptop required."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function i(s,t,l,h,d,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h2 id="what-is-the-smart-contact-mic" tabindex="-1">What is the Smart Contact Mic? <a class="header-anchor" href="#what-is-the-smart-contact-mic" aria-label="Permalink to &quot;What is the Smart Contact Mic?&quot;">​</a></h2><p>The Soniphorm Smart Contact Mic (SCM) is a contact microphone with a programmable DSP engine built into the board. Clip it to a wine glass, a spring, a radiator, a window, or your own body, and it listens to vibrations the way any contact mic does. The difference is what happens next: the signal is fed into a patch you design visually in a browser-based patcher, and from there it can drive anything. Every tap can trigger an oscillator, a drum machine, a sampler, or a MIDI note to an external synth. Every sound can be looped, sliced, granulated, resampled, or sequenced in time with the rest of the patch.</p><p>Because the SCM is reprogrammable, one device can be many things -- a sensitive instrument pickup, a field recorder, an improvised looper, a step sequencer driven by real-world taps, a MIDI trigger for a DAW, a granular sketchpad, or any combination of those at once.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Open the patcher</strong> in your browser at <a href="https://soniphorm.com/patcher" target="_blank" rel="noreferrer">soniphorm.com/patcher</a></li><li><strong>Add modules</strong> from the palette -- oscillators, filters, effects, controls</li><li><strong>Connect them</strong> by dragging cables between ports</li><li><strong>Upload</strong> to your SCM over USB</li><li><strong>Play</strong> -- drive the patch from the patcher over USB, or from an Android phone over Bluetooth MIDI</li></ol><h2 id="what-s-in-this-manual" tabindex="-1">What&#39;s in This Manual <a class="header-anchor" href="#what-s-in-this-manual" aria-label="Permalink to &quot;What&#39;s in This Manual&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Section</th><th>What You&#39;ll Find</th></tr></thead><tbody><tr><td><a href="/docs/getting-started/">Getting Started</a></td><td>What the SCM is, connect to the patcher, build your first patch</td></tr><tr><td><a href="/docs/modules/">Module Reference</a></td><td>Every module explained -- inputs, outputs, tips</td></tr><tr><td><a href="/docs/guides/">Guides</a></td><td>Step-by-step walkthroughs for common tasks</td></tr><tr><td><a href="/docs/reference/">Reference</a></td><td>Serial commands, shortcuts, troubleshooting</td></tr></tbody></table>',7)])])}const u=e(n,[["render",i]]);export{p as __pageData,u as default};
